import type { ScreenComponent } from '../../types/screen-component.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../_shared/screen-status.js';
import { AgendaService } from '../../services/agenda.service.js';
import type { AgendaList } from './agenda-list/agenda-list.component.js';
import './agenda-list/agenda-list.component.js';

export class AgendaScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private agendaList!: AgendaList;
    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

    connectedCallback(): void {
        if (!this.initialized) {
            this.initialized = true;
            this.classList.add('view-section');
            this.id = 'agenda-view';
            this.buildDom();
        }
        void this.refresh();
    }

    private buildDom(): void {
        this.statusNodes.loadingNode.textContent = 'Loading agenda…';
        this.statusNodes.errorNode.dataset.testid = 'agenda-error';
        this.statusNodes.retryNode.dataset.testid = 'agenda-retry';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.refresh(); });

        this.agendaList = document.createElement('agenda-list') as AgendaList;

        this.append(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode, this.agendaList);
    }

    private async refresh(): Promise<void> {
        this.setLoading();
        try {
            const events = await AgendaService.fetchEvents();
            this.agendaList.events = events;
            this.clearStatus();
        } catch (err) {
            this.setError(err);
        }
    }

    setLoading(): void {
        this.statusMixin.setLoading();
    }

    setError(err: unknown): void {
        this.statusMixin.setError(err);
        this.statusNodes.errorNode.textContent = `Failed to load agenda\n\n${this.statusNodes.errorNode.textContent}`;
    }

    clearStatus(): void {
        this.statusMixin.clearStatus();
    }
}

if (!customElements.get('agenda-screen')) {
    customElements.define('agenda-screen', AgendaScreen);
}
